var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"집주인이 돌아왔는데 학회장이란 자는 코빼기도 비추지 않는군요.","JPN":"家の主が戻ったというのに、学会長は顔も見せないようですわね。","ENG":"The heir is back, and this so-called President doesn't even have the courtesy to greet me.","TWN":"家主都回來了，但學會長的人影連看都看不到呢。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말이지 예의를 모르는 사람이네요. 따끔하게 혼쭐을 내야겠습니다.","JPN":"本当に無礼な方です。お灸を据えてさしあげなければなりませんわね。","ENG":"How graceless and impolite she is! I'm going to teach her a lesson when I see her.","TWN":"真是不懂禮儀的人呢，我得好好教訓她一頓才行。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"헤헷. 조금만 기다려. 내가 금방 찾아서 데려올게.","JPN":"へへっ、ちょっと待っててよ。アタシが探して連れてくるからさ。","ENG":"Heh, just wait here. I'll go bring her real quick.","TWN":"嘿嘿，請稍等。我馬上就把她找來。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도망쳐도 소용없다고 전해 두세요. 저희 가문을 모욕한 대가는 톡톡히 치러야 할 테니까요.","JPN":"逃げても無駄だとお伝えください。\\n我がマクレディー家を侮辱した対価はしっかり払っていただきますので。","ENG":"You tell her that it'd be of no use trying to run away. She's going to pay dearly for insulting my family like this.","TWN":"請幫我轉告她，就算逃跑也是沒用的。侮辱我的家族是要付出代價的。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"마을도 그렇지만...... 저택도 옛날 모습 그대로네.","JPN":"町もそうだけど……屋敷も昔のままね。","ENG":"It was the same with the village, but the mansion looks just how it used to.","TWN":"村莊也是……宅邸也是以前的模樣呢。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 책장, 아직 남아 있었구나.","JPN":"この本棚、まだあったのね。","ENG":"This bookcase... It's still here.","TWN":"這個書櫃，也還留著啊。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 이 책들을 주의 깊게 살펴 보세요.","JPN":"さあ、これらの本を注意深く読んでください。","ENG":"Now, look at these books carefully.","TWN":"來，請記得要好好留意一下這些書。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"한 권씩 읽으면 흥미 위주로 쓰여진 것 같지만, 사실은 아니랍니다.","JPN":"一冊ずつ読むと興味本位で書かれた本のように見えますが、実は違います。","ENG":"If you read them one by one, they might seem to have been written just for the fun of it.","TWN":"如果妳一本一本地讀下去，可能會覺得這些書是基於興趣寫出來的，但事實並非如此。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"행간과 행간, 단어와 단어 사이에 은밀하게 숨겨진 지식들을 하나로 엮어 가다 보면......","JPN":"行間と行間、単語と単語の間に秘められた知識を繋ぎ合わせていくと……","ENG":"But by reading between the lines and sewing the fragments of knowledge hidden between words back together,","TWN":"只要把隱藏在句子和句子之間，單字和單字之間的知識串聯在一起……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"진실된 세계를 엿볼 수 있는 시야를 얻게 되죠.","JPN":"真実の世界を見ることができるようになります。","ENG":"you'll be able to gain an insight deep enough to peek through the world of truth.","TWN":"就可以獲得窺見真正世界的視野。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"지금은 이해하기 어렵겠지만, 언젠가 알게 되는 날이 올 거예요.","JPN":"今は理解できなくても、いつか分かる時が来るはずです。","ENG":"You're too young to understand now, but you'll definitely get there in the future.","TWN":"雖然現在妳還很難理解，但妳總有一天會懂的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"위조한 고문서에, 시시한 음모론 책, 철지난 공포 소설까지......","JPN":"偽造された古文書に、くだらない陰謀論、流行りの過ぎたホラー小説まで……","ENG":"Forged old manuscripts, ridiculous conspiracy theories, unpopular horror stories...","TWN":"偽造的古文書、無聊的陰謀論書籍、甚至還有過時的恐怖小說……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이런 종이 뭉치들 속에서 뭘 알아낼 수 있겠어.","JPN":"こんな紙の束から何が分かるっていうのかしら。","ENG":"What is there to get from these random collection of books?","TWN":"從這堆紙張中，到底能明白些什麼呢。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아버지도...... 아니, 어머니께서 해 주신 얘기였나?","JPN":"お父様も……いいえ、お母様から聞いた話だったかしら？","ENG":"Dad told me—no, was it Mom who told me that?","TWN":"父親也……不，是母親告訴我的嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하긴, 누가 말해 줬는지가 뭐 중요하겠어.","JPN":"まあ、誰から聞いたかは重要ではないけれど。","ENG":"Well, who cares who said it?","TWN":"說起來，是誰告訴我的也沒什麼重要。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 왜 이리 춥지......? 벽난로에 불을 지펴야 하나?","JPN":"ところで、どうしてこんなに寒いの……？　暖炉に火を付けようかしら？","ENG":"Brrr, why is it so cold? Should I fire up the furnace?","TWN":"但是為什麼這麼冷……？該給壁爐生個火嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};